#!/usr/bin/env python3
import json,os,math
from datetime import datetime
CONFIG = json.load(open(os.path.expanduser("~/prospect2-master/config.json")))
COULEUR_PRINCIPALE = CONFIG["client"]["couleur_primaire"]
FICHIER_JSON=os.path.join(CONFIG["chemins"]["base"], CONFIG["chemins"]["dashboard"], "leads_dashboard.json")
FICHIER_SORTIE=os.path.join(CONFIG["chemins"]["base"], CONFIG["chemins"]["dashboard"], "dashboard_leads.html")
SOUMISSIONS_JSON=os.path.join(CONFIG["chemins"]["base"], CONFIG["chemins"]["dashboard"], "soumissions.json")
LOGO=""

COLS={"Nouveau":"#29B6F6","Reporter":"#FFB300","A suivre":"#7C3AED","Boite vocale":"#64748B","Vendu":"#16A34A","Annuler":"#EF4444","Soumission à faire":"#FF6D00","Soumission faite":"#4CAF50","FB":"#1877F2","Web":"#00A86B"}
STATUTS=["Nouveau","Soumission à faire","Soumission faite","A suivre","Reporter","Boite vocale","Vendu","Annuler"]
def col(k): return COLS.get(k,COULEUR_PRINCIPALE)
def badge(t,k):
    c=col(k)
    return '<span style="background:'+c+'22;color:'+c+';padding:2px 9px;border-radius:10px;font-size:11px;font-weight:700">'+t+'</span>'
def bk(b):
    b=str(b).lower()
    if "40" in b or "60" in b: return "40k+"
    if "20" in b or "30" in b: return "20k"
    return "10k"
def fmt(d):
    d=str(d).strip()
    if len(d)>=10: return d[8:10]+"/"+ d[5:7]+"/"+d[:4]
    if len(d)==7: return d[5:7]+"/"+ d[:4]
    return d
def load():
    if not os.path.exists(FICHIER_JSON): return []
    with open(FICHIER_JSON,"r",encoding="utf-8") as f: return json.load(f)
def menu(stat,uid,lid):
    cs=col(stat)
    items=""
    for s in STATUTS:
        sc=col(s)
        ul="text-decoration:underline;" if s==stat else ""
        items+='<div onclick="setS('+chr(39)+uid+chr(39)+','+chr(39)+s+chr(39)+','+chr(39)+sc+chr(39)+','+str(lid)+')" style="padding:7px 14px;cursor:pointer;background:'+sc+';color:#fff;font-size:11px;font-weight:700;'+ul+'">'+s+'</div>'
    return ('<div id="'+uid+'" style="position:relative;display:inline-block">'
            '<div onclick="toggleDD('+chr(39)+uid+chr(39)+')" style="background:'+cs+';color:#fff;border-radius:8px;padding:4px 10px;font-size:11px;font-weight:700;cursor:pointer;min-width:110px">'+stat+' &#9660;</div>'
            '<div id="'+uid+'_m" style="display:none;position:absolute;top:100%;left:0;z-index:999;border-radius:8px;overflow:hidden;box-shadow:0 4px 16px rgba(0,0,0,0.25);min-width:130px">'+items+'</div>'
            '</div>')
JS='<script>function toggleDD(id){var m=document.getElementById(id+"_m");document.querySelectorAll("[id$=\'_m\']").forEach(function(el){if(el.id!==id+"_m")el.style.display="none";});m.style.display=m.style.display==="none"?"block":"none";}function setS(id,val,color,lid){var btn=document.querySelector("#"+id+">div:first-child");btn.textContent=val+" \u25BC";btn.style.background=color;document.getElementById(id+"_m").style.display="none";if(lid){fetch("http://localhost:7373/update-statut",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({id:lid,statut:val})}).catch(function(e){console.warn("Erreur maj statut",e);});}}document.addEventListener("click",function(e){if(!e.target.closest("[id^=\'dd_\']"))document.querySelectorAll("[id$=\'_m\']").forEach(function(el){el.style.display="none";});});</script>'
def main():
    print("Generation --",datetime.now().strftime("%Y-%m-%d %H:%M"))
    leads=load()
    leads.sort(key=lambda l: str(l.get("date","")), reverse=True)
    print(" ",len(leads),"leads")
    total=len(leads)
    fb=sum(1 for l in leads if l.get("source")=="FB")
    web=sum(1 for l in leads if l.get("source")=="Web")
    vendu=sum(1 for l in leads if l.get("statut")=="Vendu")
    taux=round(vendu/total*100) if total else 0
    now=datetime.now().strftime("%Y-%m-%d %H:%M")
    bud={}
    for l in leads:
        k=bk(l.get("budget",""))
        bud[k]=bud.get(k,0)+1
    sta={}
    for l in leads:
        k=l.get("statut","Nouveau")
        sta[k]=sta.get(k,0)+1
    reg={}
    for l in leads:
        k=l.get("region","Autre")
        reg[k]=reg.get(k,0)+1
    reg_s=sorted(reg.items(),key=lambda x:-x[1])
    mo={}
    for l in leads:
        d=str(l.get("date",""))[:7]
        if len(d)==7: mo[d]=mo.get(d,0)+1
    mo_s=sorted(mo.items())
    rows=""
    for idx,l in enumerate(leads):
        bg="#fff" if idx%2==0 else "#FAFBFD"
        nom=l.get("nom","")
        tel=l.get("tel","")
        email=l.get("courriel","")
        ville=l.get("ville","")
        date=fmt(l.get("date",""))
        src=l.get("source","")
        stat=l.get("statut","Nouveau")
        budg=bk(l.get("budget",""))
        uid="dd_"+str(idx)
        dd=menu(stat,uid,l.get("id",""))
        rows+=('<tr style="background:'+bg+';border-bottom:1px solid #E8ECF4">'
               '<td style="padding:8px 12px;font-weight:600;color:#1B3A6B;white-space:nowrap">'+nom+'</td>'
               '<td style="padding:8px 12px;color:#8895AA;font-size:12px;white-space:nowrap">'+tel+'</td>'
               '<td style="padding:8px 12px;color:#8895AA;font-size:12px">'+email+'</td>'
               '<td style="padding:8px 12px">'+badge(budg,budg)+'</td>'
               '<td style="padding:8px 12px;color:#8895AA;font-size:12px;white-space:nowrap">'+date+'</td>'
               '<td style="padding:8px 12px;color:#2D3748;white-space:nowrap">'+ville+'</td>'
               '<td style="padding:8px 12px">'+badge(src,src)+'</td>'
               '<td style="padding:8px 12px">'+dd+'</td>'
               '</tr>')
    bmax=max(bud.values()) if bud else 1
    bb=""
    for k,c2 in [("10k","#29B6F6"),("20k",COULEUR_PRINCIPALE),("40k+","#FF7043")]:
        v=bud.get(k,0); p=round(v/bmax*100) if bmax else 0
        bb+=('<div style="margin-bottom:12px"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span style="font-weight:600">'+k+'</span><b style="color:#1B3A6B">'+str(v)+'</b></div><div style="height:26px;background:#E8ECF4;border-radius:6px;overflow:hidden"><div style="height:26px;width:'+str(p)+'%;background:'+c2+';border-radius:6px"></div></div></div>')
    smax=max(sta.values()) if sta else 1
    bs=""
    for s in STATUTS:
        v=sta.get(s,0)
        if not v: continue
        p=round(v/smax*100); c2=col(s)
        bs+=('<div style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>'+s+'</span><b style="color:#1B3A6B">'+str(v)+'</b></div><div style="height:8px;background:#E8ECF4;border-radius:4px"><div style="height:8px;width:'+str(p)+'%;background:'+c2+';border-radius:4px"></div></div></div>')
    stat_cards=""
    for s in STATUTS:
        v=sta.get(s,0); c2=col(s); pct=round(v/total*100) if total else 0
        stat_cards+=('<div style="border-radius:10px;border:1px solid #E8ECF4;border-left:4px solid '+c2+';padding:14px 16px;background:#fff">'
            '<div style="font-size:10px;font-weight:700;color:#8895AA;text-transform:uppercase;letter-spacing:.8px;margin-bottom:6px">'+s+'</div>'
            '<div style="font-size:34px;font-weight:800;color:#1B3A6B;line-height:1">'+str(v)+'</div>'
            '<div style="font-size:11px;color:#8895AA;margin:4px 0 8px">'+str(pct)+'% du total</div>'
            '<div style="height:4px;background:#E8ECF4;border-radius:2px"><div style="height:4px;width:'+str(pct)+'%;background:'+c2+';border-radius:2px"></div></div>'
            '</div>')
    sec_statut=('<div class="card" style="margin-bottom:16px">'
        '<div class="ttl" style="margin-bottom:14px">Répartition par statut</div>'
        '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:12px">'+stat_cards+'</div>'
        '</div>')
    rcols=[COULEUR_PRINCIPALE,"#1877F2","#00A86B","#7C3AED"]
    br=""
    rmax=reg_s[0][1] if reg_s else 1
    for i,(r,v) in enumerate(reg_s):
        p=round(v/rmax*100)
        br+=('<div style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>'+r+'</span><b style="color:#1B3A6B">'+str(v)+'</b></div><div style="height:7px;background:#E8ECF4;border-radius:4px"><div style="height:7px;width:'+str(p)+'%;background:'+rcols[i%4]+';border-radius:4px"></div></div></div>')
    if mo_s:
        vals=[v for _,v in mo_s]; labs=[m.replace("-","/") for m,_ in mo_s]
        vmax=max(vals) if vals else 1; W,H=560,110; n=len(vals); pts=[]
        for i,v in enumerate(vals):
            x=30+i*(W-40)//max(n-1,1); y=H-15-int((v/vmax)*(H-25)); pts.append((x,y))
        pl=" ".join(str(x)+","+str(y) for x,y in pts)
        cirs="".join('<circle cx="'+str(x)+'" cy="'+str(y)+'" r="5" fill="'+COULEUR_PRINCIPALE+'"/>' for x,y in pts)
        xlbs="".join('<text x="'+str(x)+'" y="'+str(H)+'" text-anchor="middle" font-size="9" fill="#8895AA">'+labs[i]+'</text>' for i,(x,y) in enumerate(pts))
        courbe='<svg viewBox="0 0 '+str(W)+' '+str(H)+'" style="width:100%;height:auto"><polyline points="'+pl+'" fill="none" stroke="'+COULEUR_PRINCIPALE+'" stroke-width="3"/>'+cirs+xlbs+'</svg>'
    else: courbe="<p>Aucune donnee</p>"
    def arc(pct,start,color,r=55):
        if pct<=0: return ""
        if pct>=1: pct=0.9999
        end=start+pct*360; sr,er=start*math.pi/180,end*math.pi/180; cx,cy=70,70
        x1=cx+r*math.cos(sr); y1=cy+r*math.sin(sr); x2=cx+r*math.cos(er); y2=cy+r*math.sin(er)
        lg=1 if pct>0.5 else 0
        return '<path d="M'+str(cx)+','+str(cy)+' L'+str(round(x1,1))+','+str(round(y1,1))+' A'+str(r)+','+str(r)+' 0 '+str(lg)+',1 '+str(round(x2,1))+','+str(round(y2,1))+' Z" fill="'+color+'"/>'
    fp=fb/total if total else 0; wp=web/total if total else 0
    cam=('<svg viewBox="0 0 140 140" style="width:140px;height:140px">'+arc(fp,-90,"#1877F2")+arc(wp,-90+fp*360,"#00A86B")+'<circle cx="70" cy="70" r="28" fill="white"/><text x="70" y="75" text-anchor="middle" font-size="14" font-weight="bold" fill="#1B3A6B">'+str(total)+'</text></svg>')
    html=('<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Dashboard</title>'
          '<style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:-apple-system,sans-serif;background:#F8F9FC}'
          '.card{background:#fff;border-radius:14px;padding:22px;box-shadow:0 1px 8px rgba(27,58,107,.07);border:1px solid #E8ECF4}'
          '.g4{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:20px}'
          '.g3{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-bottom:16px}'
          '.g2{display:grid;grid-template-columns:2fr 1fr;gap:16px;margin-bottom:16px}'
          '.kpi{border-left:4px solid var(--c)}'
          '.ttl{font-size:11px;font-weight:700;color:#8895AA;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:14px}'
          'table{width:100%;border-collapse:collapse;font-size:13px}'
          'th{padding:10px 12px;color:#fff;text-align:left;font-size:11px;text-transform:uppercase;font-weight:700;background:#1B3A6B;position:sticky;top:0}'
          '</style></head><body>'+JS+
          '<div style="background:#fff;border-bottom:1px solid #E8ECF4;padding:12px 28px;display:flex;justify-content:space-between;align-items:center">'
          '<div style="display:flex;align-items:center;gap:16px">'
          '<img src="data:image/png;base64,'+LOGO+'" style="height:44px;object-fit:contain">'
          '<div style="width:1px;height:32px;background:#E8ECF4"></div>'
          '<div><div style="font-size:10px;color:#8895AA;text-transform:uppercase;font-weight:600">Tableau de bord</div>'
          '<div style="font-size:16px;font-weight:800;color:#1B3A6B">Leads 2026</div></div></div>'
          '<div style="font-size:12px;color:#8895AA">'+now+'</div></div>'
          '<div style="padding:24px 28px;max-width:1320px;margin:0 auto">'
          '<div class="g4">'
          '<div class="card kpi" style="--c:'+COULEUR_PRINCIPALE+'"><div style="font-size:11px;color:#8895AA;text-transform:uppercase;font-weight:600">Total</div><div style="font-size:38px;font-weight:800;color:#1B3A6B;margin-top:4px">'+str(total)+'</div></div>'
          '<div class="card kpi" style="--c:#1877F2"><div style="font-size:11px;color:#8895AA;text-transform:uppercase;font-weight:600">Facebook</div><div style="font-size:38px;font-weight:800;color:#1B3A6B;margin-top:4px">'+str(fb)+'</div><div style="font-size:12px;color:#8895AA">'+str(round(fb/total*100) if total else 0)+'%</div></div>'
          '<div class="card kpi" style="--c:#00A86B"><div style="font-size:11px;color:#8895AA;text-transform:uppercase;font-weight:600">Web</div><div style="font-size:38px;font-weight:800;color:#1B3A6B;margin-top:4px">'+str(web)+'</div><div style="font-size:12px;color:#8895AA">'+str(round(web/total*100) if total else 0)+'%</div></div>'
          '<div class="card kpi" style="--c:#16A34A"><div style="font-size:11px;color:#8895AA;text-transform:uppercase;font-weight:600">Vendus</div><div style="font-size:38px;font-weight:800;color:#1B3A6B;margin-top:4px">'+str(vendu)+'</div><div style="font-size:12px;color:#8895AA">'+str(taux)+'%</div></div>'
          '</div>'
          '<div class="g3">'
          '<div class="card"><div class="ttl">Provenance</div><div style="display:flex;justify-content:center;gap:28px;margin-bottom:10px">'
          '<div style="text-align:center"><div style="width:12px;height:12px;border-radius:3px;background:#1877F2;margin:0 auto 4px"></div><div style="font-size:13px;font-weight:800;color:#1877F2">FB</div><div style="font-size:28px;font-weight:800;color:#1B3A6B">'+str(fb)+'</div></div>'
          +cam+
          '<div style="text-align:center"><div style="width:12px;height:12px;border-radius:3px;background:#00A86B;margin:0 auto 4px"></div><div style="font-size:13px;font-weight:800;color:#00A86B">Web</div><div style="font-size:28px;font-weight:800;color:#1B3A6B">'+str(web)+'</div></div>'
          '</div></div>'
          '<div class="card"><div class="ttl">Budget</div>'+bb+'</div>'
          '<div class="card"><div class="ttl">Statut</div>'+bs+'</div>'
          '</div>'
          '<div class="g2">'
          '<div class="card"><div class="ttl">Par mois</div>'+courbe+'</div>'
          '<div class="card"><div class="ttl">Par region</div>'+br+'</div>'
          '</div>'
          +sec_statut+
          '<div class="card"><div class="ttl" style="margin-bottom:14px">Liste — '+str(total)+' leads</div>'
          '<div style="overflow-x:auto;max-height:420px;overflow-y:auto;border-radius:10px;border:1px solid #E8ECF4">'
          '<table><thead><tr><th>Nom</th><th>Tel</th><th>Courriel</th><th>Budget</th><th>Date</th><th>Ville</th><th>Source</th><th>Statut</th></tr></thead>'
          '<tbody>'+rows+'</tbody></table></div></div>'
          '</div></body></html>')
    with open(FICHIER_SORTIE,"w",encoding="utf-8") as f: f.write(html)
    print("  OK:",FICHIER_SORTIE)
def _patch_soumissions(html_path):
    import json as _j
    from email.utils import parsedate_to_datetime as _pdt
    soum_data = []
    if os.path.exists(SOUMISSIONS_JSON):
        with open(SOUMISSIONS_JSON, "r", encoding="utf-8") as f:
            soum_data = _j.load(f)
    def _ts(s):
        try: return _pdt(s.get("date_reception","")).timestamp()
        except: return 0
    soum_data = sorted(soum_data, key=_ts, reverse=True)

    with open(html_path, "r", encoding="utf-8") as f:
        c = f.read()

    # CSS soumissions
    CSS = (
        ".sol-nav{display:flex;gap:0;border-bottom:2px solid #E8ECF4;margin-bottom:0;padding:0 28px;background:#fff}"
        ".sol-nav-btn{background:none;border:none;padding:14px 22px;font-size:13px;font-weight:700;color:#8895AA;cursor:pointer;border-bottom:3px solid transparent;margin-bottom:-2px}"
        ".sol-nav-btn.on,.sol-nav-btn:hover{color:#1B3A6B;border-bottom-color:"+COULEUR_PRINCIPALE+"}"
        ".sol-pane{display:none}.sol-pane.on{display:block}"
        ".sol-ov{display:none;position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:1000;align-items:center;justify-content:center}"
        ".sol-ov.on{display:flex}"
        ".sol-mo{background:#fff;border-radius:16px;padding:28px 32px;max-width:540px;width:95%;max-height:85vh;overflow-y:auto;position:relative}"
        ".sol-mh{display:flex;justify-content:space-between;align-items:center;margin-bottom:18px}"
        ".sol-mh-t{font-size:17px;font-weight:800;color:#1B3A6B}"
        ".sol-mx{background:none;border:none;font-size:22px;cursor:pointer;color:#8895AA;line-height:1}"
        ".sol-mf{margin-bottom:10px}"
        ".sol-ml{font-size:10px;font-weight:700;color:#8895AA;text-transform:uppercase;letter-spacing:.6px;margin-bottom:2px}"
        ".sol-mv{font-size:14px;color:#1B3A6B;font-weight:600}"
        ".sol-md{font-size:12px;color:#475569;white-space:pre-wrap;max-height:120px;overflow-y:auto;border:1px solid #E8ECF4;border-radius:6px;padding:8px}"
        ".soum-wrap{padding:24px 28px;max-width:1320px;margin:0 auto}"
        ".soum-bar{display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;flex-wrap:wrap;gap:10px}"
        ".soum-count{font-size:13px;color:#8895AA;font-weight:600}"
        ".soum-scan{background:#1B3A6B;color:"+COULEUR_PRINCIPALE+";border:none;border-radius:8px;padding:10px 20px;font-size:13px;font-weight:700;cursor:pointer}"
        ".soum-scan:hover{opacity:.88}.soum-scan:disabled{opacity:.5;cursor:default}"
        ".soum-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(310px,1fr));gap:14px}"
        ".soum-card{background:#fff;border-radius:14px;padding:18px 20px 14px;border:1px solid #E8ECF4;border-left:5px solid #CBD5E1;box-shadow:0 1px 8px rgba(27,58,107,.07);cursor:pointer;transition:box-shadow .15s}"
        ".soum-card:hover{box-shadow:0 4px 16px rgba(27,58,107,.14)}"
        ".soum-card.st-faire{border-left-color:#EF4444}.soum-card.st-attente{border-left-color:#F59E0B}"
        ".soum-card.st-envoye{border-left-color:#3B82F6}.soum-card.st-gagne{border-left-color:#16A34A}"
        ".soum-card.st-perdu{border-left-color:#94A3B8}.soum-card.st-distributeur{border-left-color:#9333EA}"
        ".soum-card.st-partenaire{border-left-color:#1E3A8A}.soum-card.st-abandonner{border-left-color:#4B5563}"
        ".soum-no{font-size:10px;font-weight:800;color:"+COULEUR_PRINCIPALE+";letter-spacing:.6px;margin-bottom:3px}"
        ".soum-nom{font-size:15px;font-weight:800;color:#1B3A6B;margin-bottom:2px}"
        ".soum-tel{font-size:12px;color:#64748B;margin-bottom:3px}"
        ".soum-badge{display:inline-block;font-size:10px;background:#EEF2FB;color:#1B3A6B;padding:2px 8px;border-radius:8px;font-weight:600;margin-bottom:6px}"
        ".soum-desc{font-size:12px;color:#94A3B8;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-bottom:10px}"
        ".soum-foot{display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:6px}"
        ".soum-date{font-size:11px;color:#CBD5E1}"
        ".soum-btns{display:flex;flex-wrap:wrap;gap:4px}"
        ".soum-btn{border:1.5px solid currentColor;border-radius:6px;padding:3px 9px;font-size:11px;font-weight:700;cursor:pointer;background:transparent;transition:background .12s,color .12s}"
        ".soum-btn.on{background:currentColor}.soum-btn.on span{filter:invert(1)}.soum-btn span{display:block}"
        ".soum-stats{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:16px}"
        ".soum-stat-chip{display:flex;align-items:center;gap:6px;background:#fff;border:1.5px solid #E8ECF4;border-radius:20px;padding:5px 12px;font-size:11px;font-weight:700;color:#475569}"
        ".soum-stat-dot{display:inline-block;width:8px;height:8px;border-radius:50%}"
        ".soum-stat-n{font-size:14px;font-weight:800;color:#1B3A6B;margin-left:2px}"
        ".soum-empty{text-align:center;padding:60px 20px;color:#94A3B8;font-size:14px}"
        ".c-faire{color:#EF4444}.c-attente{color:#F59E0B}.c-envoye{color:#3B82F6}"
        ".c-gagne{color:#16A34A}.c-perdu{color:#94A3B8}.c-distributeur{color:#9333EA}"
        ".c-partenaire{color:#1E3A8A}.c-abandonner{color:#4B5563}"
    )
    c = c.replace('</style></head>', CSS + '</style></head>', 1)

    # Données soumissions inline
    inline = '<script>var _SOUM_DATA=' + _j.dumps(soum_data, ensure_ascii=False) + ';</script>'
    c = c.replace('</head>', inline + '</head>', 1)

    # JS soumissions
    JS_SOUM = (
        '<script>'
        'var _SC=[];'
        'var _SM={'
          '"\u00c0 faire":{cls:"faire",color:"#EF4444"},'
          '"En attente":{cls:"attente",color:"#F59E0B"},'
          '"Soumission envoy\u00e9e":{cls:"envoye",color:"#3B82F6"},'
          '"Gagn\u00e9":{cls:"gagne",color:"#16A34A"},'
          '"Perdu":{cls:"perdu",color:"#94A3B8"},'
          '"Distributeur":{cls:"distributeur",color:"#9333EA"},'
          '"Partenaire":{cls:"partenaire",color:"#1E3A8A"},'
          '"Abandonner":{cls:"abandonner",color:"#4B5563"}'
        '};'
        'function _se(s){return String(s||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");}'
        'function _fd(s){try{return new Date(s).toLocaleDateString("fr-CA",{year:"numeric",month:"short",day:"numeric"});}catch(e){return s||"";}}'
        'function _btns(mid,statut,ctx){'
          'return Object.entries(_SM).map(function(e){'
            'var k=e[0],v=e[1],on=(k===statut?" on":"");'
            'return\'<button class="soum-btn c-\'+v.cls+on+\'" style="color:\'+v.color+\'" \''
              '+\'onclick="event.stopPropagation();solSt(\\\'\'+ _se(mid)+\'\\\',\\\'\'+ _se(k)+\'\\\',\\\'\'+ ctx+\'\\\')">\''
              '+\'<span>\'+_se(k)+\'</span></button>\';'
          '}).join("");'
        '}'
        'function _card(s){'
          'var st=_SM[s.statut]||{cls:"faire",color:"#EF4444"};'
          'var mid=_se(s.msg_id);'
          'var desc=(s.description||"").replace(/\\n/g," ").trim();'
          'var h=\'<div class="soum-card st-\'+st.cls+\'" onclick="solOpen(\\\'\'+ mid+\'\\\')">\';'
          'h+=\'<div class="soum-no">\'+_se(s.no_projet||"")+\'</div>\';'
          'h+=\'<div class="soum-nom">\'+_se(s.client||s.nom_projet||"(sans nom)")+\'</div>\';'
          'if(s.telephone)h+=\'<div class="soum-tel">\u260e\ufe0f \'+_se(s.telephone)+\'</div>\';'
          'if(s.type_travaux)h+=\'<span class="soum-badge">\'+_se(s.type_travaux)+\'</span><br>\';'
          'if(desc)h+=\'<div class="soum-desc" title="\'+_se(desc)+\'">\'+_se(desc.length>110?desc.slice(0,110)+"\u2026":desc)+\'</div>\';'
          'h+=\'<div class="soum-foot"><span class="soum-date">\'+_fd(s.date_reception)+\'</span>\';'
          'h+=\'<div class="soum-btns">\'+_btns(s.msg_id,s.statut,"card")+\'</div></div></div>\';'
          'return h;'
        '}'
        'function _renderStats(){'
          'var counts={};'
          '_SC.forEach(function(s){var k=s.statut||"\u00c0 faire";counts[k]=(counts[k]||0)+1;});'
          'var st=document.getElementById("soum-stats");'
          'if(st)st.innerHTML=Object.entries(_SM).filter(function(e){return counts[e[0]];}).map(function(e){'
            'var k=e[0],v=e[1];'
            'return\'<div class="soum-stat-chip"><span class="soum-stat-dot" style="background:\'+v.color+\'"></span>\'+k+\'<span class="soum-stat-n">\'+counts[k]+\'</span></div>\';'
          '}).join("");'
        '}'
        'function _renderGrid(){'
          'var g=document.getElementById("soum-grid");'
          'var cnt=document.getElementById("soum-count");'
          'if(!_SC.length){'
            'g.innerHTML=\'<p class="soum-empty">Aucune soumission.\u2003Cliquez sur Scanner pour importer les courriels.</p>\';'
            'if(cnt)cnt.textContent="";'
            'var st=document.getElementById("soum-stats");if(st)st.innerHTML="";'
            'return;'
          '}'
          'g.innerHTML=_SC.map(_card).join("");'
          'if(cnt)cnt.textContent=_SC.length+" soumission"+(_SC.length>1?"s":"");'
          '_renderStats();'
        '}'
        'async function solLoad(){'
          'var g=document.getElementById("soum-grid");'
          'if(location.protocol==="file:"){'
            'if(typeof _SOUM_DATA!=="undefined"){_SC=_SOUM_DATA;_renderGrid();}'
            'else{g.innerHTML=\'<p class="soum-empty">Cliquez sur Scanner pour charger les soumissions.</p>\';document.getElementById("soum-count").textContent="";}return;'
          '}'
          'try{'
            'var r=await fetch("http://localhost:7373/soumissions");'
            '_SC=await r.json();_renderGrid();'
          '}catch(e){'
            'g.innerHTML=\'<p class="soum-empty" style="color:#EF4444">Serveur indisponible \u2014 assurez-vous que dashboard_server.py tourne.</p>\';'
          '}'
        '}'
        'async function solScan(){'
          'var b=document.getElementById("soum-scan");'
          'b.disabled=true;b.textContent="Scan en cours\u2026";'
          'if(location.protocol==="file:"){'
            'window.location.href="solarium-scan://scan";'
            'setTimeout(function(){'
              'var old=document.querySelector(\'script[src^="soumissions.js"]\');'
              'if(old)old.remove();'
              'var sc=document.createElement("script");'
              'sc.src="soumissions.js?t="+Date.now();'
              'sc.onload=function(){_SC=_SOUM_DATA;_renderGrid();b.textContent="\u21bb\u00a0 Scanner les nouveaux dossiers";b.disabled=false;};'
              'sc.onerror=function(){b.textContent="\u21bb\u00a0 Scanner les nouveaux dossiers";b.disabled=false;};'
              'document.head.appendChild(sc);'
            '},4000);return;'
          '}'
          'try{'
            'var r=await fetch("http://localhost:7373/scanner",{method:"POST",headers:{"Content-Type":"application/json"},body:"{}"});'
            'var d=await r.json();'
            'if(d.ok){await solLoad();b.textContent="\u2713 "+d.nouveaux+" nouveau(x)";setTimeout(function(){b.textContent="\u21bb\u00a0 Scanner les nouveaux dossiers";b.disabled=false;},2800);}'
            'else{b.textContent="\u2717 Erreur";b.disabled=false;alert("Erreur : "+(d.error||JSON.stringify(d)));}'
          '}catch(e){b.textContent="\u2717 Serveur indisponible";b.disabled=false;}'
        '}'
        'async function solSt(mid,statut,ctx){'
          'var s=_SC.find(function(x){return x.msg_id===mid;});'
          'if(s){s.statut=statut;s.date_statut=new Date().toISOString();}'
          'if(location.protocol==="file:"){_renderGrid();if(ctx==="modal")solOpen(mid);}'
          'try{'
            'await fetch("http://localhost:7373/update-soumission-statut",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({msg_id:mid,statut:statut})});'
          '}catch(e){}'
          'await solLoad();if(ctx==="modal")solOpen(mid);'
        '}'
        'function solOpen(mid){'
          'var s=_SC.find(function(x){return x.msg_id===mid;});if(!s)return;'
          'document.getElementById("sol-mh-t").textContent=s.no_projet||s.nom_projet||s.client||"Dossier";'
          'function mf(l,v){if(!v)return"";return\'<div class="sol-mf"><div class="sol-ml">\'+l+\'</div><div class="sol-mv">\'+_se(v)+\'</div></div>\';}'
          'document.getElementById("sol-mb").innerHTML='
            'mf("Num\u00e9ro de projet",s.no_projet)'
            '+mf("Nom du projet",s.nom_projet)'
            '+mf("Client",s.client)'
            '+mf("Adresse",s.adresse)'
            '+mf("T\u00e9l\u00e9phone",s.telephone)'
            '+mf("Type de travaux",s.type_travaux)'
            '+mf("Date re\u00e7ue",_fd(s.date_reception))'
            '+(s.description?\'<div class="sol-mf"><div class="sol-ml">Description</div><div class="sol-md">\'+_se(s.description)+\'</div></div>\':"");'
          'document.getElementById("sol-ms-btns").innerHTML=_btns(mid,s.statut,"modal");'
          'document.getElementById("sol-ov").classList.add("on");'
          'document.body.style.overflow="hidden";'
        '}'
        'function solMx(){document.getElementById("sol-ov").classList.remove("on");document.body.style.overflow="";}'
        'function solMxSi(e){if(e.target===e.currentTarget)solMx();}'
        'function solTab(id,b){'
          'document.querySelectorAll(".sol-pane").forEach(function(p){p.classList.remove("on");});'
          'document.querySelectorAll(".sol-nav-btn").forEach(function(x){x.classList.remove("on");});'
          'document.getElementById("sol-"+id).classList.add("on");'
          'if(b)b.classList.add("on");'
          'if(id==="soumissions")solLoad();'
        '}'
        'window.addEventListener("load",function(){'
          'document.querySelectorAll(".sol-pane")[0].classList.add("on");'
          'document.querySelectorAll(".sol-nav-btn")[0].classList.add("on");'
        '});'
        '</script>'
    )
    c = c.replace('</body>', JS_SOUM + '</body>', 1)

    # Remplacer le <body> ouvert par nav + pane leads + pane soumissions
    NAV = (
        '<div class="sol-nav">'
          '<button class="sol-nav-btn" onclick="solTab(\'leads\',this)">Leads</button>'
          '<button class="sol-nav-btn" onclick="solTab(\'soumissions\',this)">Soumissions</button>'
        '</div>'
        '<div id="sol-leads" class="sol-pane">'
    )
    SOUM_PANE = (
        '</div>'  # ferme sol-leads
        '<div id="sol-soumissions" class="sol-pane">'
          '<div class="soum-wrap">'
            '<div class="soum-bar">'
              '<span class="soum-count" id="soum-count"></span>'
              '<button class="soum-scan" id="soum-scan" onclick="solScan()">'
                '\u21bb\u00a0 Scanner les nouveaux dossiers'
              '</button>'
            '</div>'
            '<div id="soum-stats" class="soum-stats"></div>'
            '<div id="soum-grid" class="soum-grid">'
              '<p class="soum-empty">Chargement\u2026</p>'
            '</div>'
          '</div>'
        '</div>'
        # Modal
        '<div class="sol-ov" id="sol-ov" onclick="solMxSi(event)">'
          '<div class="sol-mo">'
            '<div class="sol-mh">'
              '<div class="sol-mh-t" id="sol-mh-t"></div>'
              '<button class="sol-mx" onclick="solMx()">&times;</button>'
            '</div>'
            '<div id="sol-mb"></div>'
            '<div style="margin-top:14px"><div class="sol-ml" style="margin-bottom:8px">Changer le statut</div>'
            '<div class="soum-btns" id="sol-ms-btns"></div></div>'
          '</div>'
        '</div>'
    )

    # Wrap le contenu existant du body dans sol-leads
    c = c.replace('<body', '<body', 1)
    # Insérer nav juste après la barre de titre (premier </div> de la topbar)
    # Chercher la fin de la topbar header
    import re as _re
    topbar_end = _re.search(r'</div>\s*<div style="padding:24px', c)
    if topbar_end:
        ins = topbar_end.start() + len('</div>')
        c = c[:ins] + NAV + c[ins:]
        # Trouver la fin du contenu leads (avant </body>)
        body_close = c.rfind('</body>')
        c = c[:body_close] + SOUM_PANE + c[body_close:]

    with open(html_path, "w", encoding="utf-8") as f:
        f.write(c)
    print("  OK: patch soumissions appliqué")

if __name__=="__main__":
    main()
    _patch_soumissions(FICHIER_SORTIE)
